def solution():
    count = 0
    # base^n can only have n digits if base < 10
    # (If base >= 10, then base^n >= 10^n, which has at least n+1 digits)
    for base in range(1, 10):
        n = 1
        while True:
            # Calculate value and check its length
            val = base**n
            if len(str(val)) == n:
                count += 1
            elif len(str(val)) < n:
                # As n increases, base^n grows slower than 10^(n-1)
                # so once it falls behind, it will never catch up
                break
            n += 1
    return count


if __name__ == "__main__":
    print(solution())
